from sympy import isprime, prime
def a(n):
    if n == 5: return 0
    spn, digits = str(prime(n)), 1
    while True:
        for sk in [d*digits for d in "1379"]:
            if isprime(t:=int(sk + spn + sk)):
                return t
        digits += 1
print([a(n) for n in range(1, 37)]) # _Michael S. Branicky_, Jun 13 2026

